package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.io.StringWriter;

import static org.junit.jupiter.api.Assertions.assertEquals;

public class CSVFormatTest {

    @Test
    public void testFormat() throws IOException {
        CSVFormat csvFormat = CSVFormat.DEFAULT;

        StringWriter out = new StringWriter();
        CSVPrinter csvPrinter = Mockito.mock(CSVPrinter.class);
        Mockito.when(csvPrinter.printRecord("value1", "value2")).thenReturn(csvPrinter);
        Mockito.when(new CSVPrinter(out, csvFormat).printRecord("value1", "value2")).thenReturn(csvPrinter);

        String result = csvFormat.format("value1", "value2");

        assertEquals("value1,value2", result.trim());
    }
}
